sql:
SELECT international_size, it_size
FROM size_conversions
WHERE product_category = 'dresses';

SELECT DISTINCT product_category 
FROM size_conversions 
WHERE gender = 'women';

SELECT product_name
FROM products
WHERE product_id IN (SELECT product_id FROM size_conversions);

SELECT product_name 
FROM products 
WHERE product_id NOT IN (
  SELECT DISTINCT product_id 
  FROM sales
);

